OVERRIDES['crontab-generator'] = """  'crontab-generator':{inputs:[{key:'minute',label:'Minute',type:'text',defaultValue:'0'},{key:'hour',label:'Hour',type:'text',defaultValue:'2'},{key:'dom',label:'Day of Month',type:'text',defaultValue:'*'},{key:'month',label:'Month',type:'text',defaultValue:'*'},{key:'dow',label:'Day of Week',type:'text',defaultValue:'*'}],formula:(v)=>{const cron=v.minute+' '+v.hour+' '+v.dom+' '+v.month+' '+v.dow;let desc='';if(v.minute==='0'&&v.hour==='2'&&v.dom==='*'&&v.dow==='*')desc='Daily at 2:00 AM';else if(v.minute==='*/5'&&v.hour==='*')desc='Every 5 minutes';else desc='Custom schedule';return[{label:'Cron',value:cron},{label:'Description',value:desc}];},presets:[{label:'Daily 2AM',values:{minute:'0',hour:'2',dom:'*',month:'*',dow:'*'}},{label:'Every 5min',values:{minute:'*/5',hour:'*',dom:'*',month:'*',dow:'*'}}],}"""

