OVERRIDES['password-strength-analyser'] = """  'password-strength-analyser':{inputs:[{key:'password',label:'Password',type:'text',defaultValue:'MyP@ssw0rd!'}],formula:(v)=>{const p=String(v.password);let cs=0;if(/[a-z]/.test(p))cs+=26;if(/[A-Z]/.test(p))cs+=26;if(/[0-9]/.test(p))cs+=10;if(/[^a-zA-Z0-9]/.test(p))cs+=32;const e=p.length*Math.log2(cs||1);const s=e<40?'Weak':e<60?'Fair':e<80?'Good':e<100?'Strong':'Very Strong';return[{label:'Strength',value:s},{label:'Entropy',value:e.toFixed(0)+' bits'},{label:'Length',value:p.length+' chars'}];},}"""

