OVERRIDES['roman-numeral-converter'] = """  'roman-numeral-converter':{inputs:[{key:'number',label:'Number (1-3999)',type:'number',defaultValue:2026,min:1,max:3999}],formula:(v)=>{const n=F(v.number);const vls=[1000,900,500,400,100,90,50,40,10,9,5,4,1];const sym=['M','CM','D','CD','C','XC','L','XL','X','IX','V','IV','I'];let r='',rem=n;for(let i=0;i<vls.length;i++)while(rem>=vls[i]){r+=sym[i];rem-=vls[i];}return[{label:'Roman',value:r}];},}"""

