OVERRIDES['mac-address-generator'] = """  'mac-address-generator':{inputs:[{key:'count',label:'Count',type:'number',defaultValue:1,min:1,max:10}],formula:(v)=>{const addrs=[];for(let i=0;i<F(v.count);i++){const b=Array.from({length:6},()=>Math.floor(Math.random()*256));b[0]=b[0]&0xFE|0x02;addrs.push(b.map(x=>x.toString(16).padStart(2,'0')).join(':'));}return[{label:'MAC',value:addrs.join('\\n')}];},}"""

