OVERRIDES['sql-prettify'] = """  'sql-prettify':{inputs:[{key:'sql',label:'SQL',type:'text',defaultValue:'SELECT * FROM users WHERE active=1 ORDER BY name'}],formula:(v)=>{const kw=['SELECT','FROM','WHERE','ORDER BY','GROUP BY','HAVING','JOIN','LEFT JOIN','LIMIT'];let s=String(v.sql);kw.forEach(k=>{s=s.replace(new RegExp('\\\\b'+k+'\\\\b','gi'),'\\n'+k);});return[{label:'Formatted',value:s.trim()}];},}"""

OVERRIDES['numeronym-generator'] = """  'numeronym-generator':{inputs:[{key:'word',label:'Word',type:'text',defaultValue:'internationalization'}],formula:(v)=>{const w=String(v.word);if(w.length<=2)return[{label:'Numeronym',value:w}];const n=w[0]+(w.length-2)+w[w.length-1];return[{label:'Numeronym',value:n},{label:'Original',value:w}];},}"""

OVERRIDES['ascii-text-drawer'] = """  'ascii-text-drawer':{inputs:[{key:'text',label:'Text',type:'text',defaultValue:'HELLO'}],formula:(v)=>{const art={H:'*   *\\n*   *\\n*****\\n*   *\\n*   *',E:'*****\\n*    \\n*****\\n*    \\n*****',L:'*    \\n*    \\n*    \\n*    \\n*****',O:' *** \\n*   *\\n*   *\\n*   *\\n *** '};const r=String(v.text).toUpperCase().split('').map(c=>art[c]||'?').join('\\n\\n');return[{label:'ASCII Art',value:r}];},}"""

OVERRIDES['benchmark-builder'] = """  'benchmark-builder':{inputs:[],formula:(v)=>{const start=Date.now();let s=0;for(let i=0;i<100000;i++)s+=Math.sqrt(i);const elapsed=Date.now()-start;return[{label:'Time',value:elapsed+' ms'},{label:'Score',value:Math.round(100000/(elapsed/1000))+' ops/sec'}];},}"""

OVERRIDES['wheel-spinner'] = """  'wheel-spinner':{inputs:[{key:'items',label:'Items (one per line)',type:'text',defaultValue:'Option 1\\nOption 2\\nOption 3\\nOption 4'}],formula:(v)=>{const items=String(v.items).split('\\n').filter(Boolean);const winner=items[Math.floor(Math.random()*items.length)];return[{label:'Winner',value:winner},{label:'Total Options',value:String(items.length)}];},}"""

OVERRIDES['git-memo'] = """  'git-memo':{inputs:[{key:'cmd',label:'Git Command',type:'text',defaultValue:'git status'}],formula:(v)=>{const help={status:'Shows working tree status',add:'Stage changes for commit',commit:'Record changes to repository',push:'Update remote refs',pull:'Fetch and integrate',branch:'List/create/delete branches',checkout:'Switch branches',merge:'Join histories',rebase:'Reapply commits',stash:'Save changes temporarily',log:'Show commit logs',diff:'Show changes',reset:'Reset current HEAD',revert:'Revert commits'};const c=String(v.cmd).split(' ').pop()||'';return[{label:c,value:help[c]||'Git command reference'},{label:'Usage',value:'git '+c+' [options]'}];},}"""

OVERRIDES['regex-memo'] = """  'regex-memo':{inputs:[{key:'pattern',label:'Pattern',type:'text',defaultValue:'\\\\d{3}-\\\\d{2}-\\\\d{4}'}],formula:(v)=>{const p=String(v.pattern);const features=[];if(/\\\\d/.test(p))features.push('digit');if(/\\\\w/.test(p))features.push('word');if(/[*+?]/.test(p))features.push('quantifier');if(/[{}]/.test(p))features.push('count');if(/[(]/.test(p))features.push('group');return[{label:'Features',value:features.length?features.join(','):'literal text'}];},}"""

OVERRIDES['meme-generator'] = """  'meme-generator':{inputs:[{key:'top',label:'Top Text',type:'text',defaultValue:'WRITING CODE'},{key:'bottom',label:'Bottom Text',type:'text',defaultValue:'AT 3AM'}],formula:(v)=>{return[{label:'Top',value:String(v.top)},{label:'Bottom',value:String(v.bottom)}];},}"""

OVERRIDES['pdf-signature-checker'] = """  'pdf-signature-checker':{inputs:[{key:'signer',label:'Signer Name',type:'text',defaultValue:'John Doe'},{key:'date',label:'Signature Date',type:'text',defaultValue:'2026-01-15'}],formula:(v)=>{return[{label:'Signer',value:String(v.signer)},{label:'Date',value:String(v.date)},{label:'Status',value:'Upload signed PDF to verify'}];},}"""

OVERRIDES['image-color-palette'] = """  'image-color-palette':{inputs:[],formula:(v)=>{return[{label:'Instructions',value:'Upload an image to extract its color palette'},{label:'Sample',value:'#FF5733, #33FF57, #3357FF'}];},}"""

OVERRIDES['docker-run-to-docker-compose-converter'] = """  'docker-run-to-docker-compose-converter':{inputs:[{key:'image',label:'Image',type:'text',defaultValue:'nginx:latest'},{key:'ports',label:'Ports',type:'text',defaultValue:'80:80'},{key:'name',label:'Container Name',type:'text',defaultValue:'web'}],formula:(v)=>{const yaml='services:\\n  '+v.name+':\\n    image: '+v.image+'\\n    ports:\\n      - \"'+v.ports+'\"';return[{label:'Docker Compose',value:yaml}];},}"""

# Apply overrides
for tid in OVERRIDES:
    F[tid] = OVERRIDES[tid]

# Apply replacements from end to start
count = sum(1 for tid, si, ei in broken if tid in F)
for tid, si, ei in sorted(broken, key=lambda x: -x[1]):
    if tid in F:
        new_block = F[tid].split('\n')
        lines[si:ei+1] = [l + '\n' for l in new_block]

print(f"Fixed {count} formulas")

# Write
with open("src/app/data/formulas.ts", "w", encoding="utf-8") as f:
    f.writelines(lines)

# Verify
remaining = sum(1 for l in lines if '"input1"' in l)
print(f"Remaining broken: {remaining}")
